#include <stdio.h>
int main() {
    int T, N, i, j, k, count, max_count;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int matrix[N][N];
        for (i = 0; i < N; i++) {
            for (j = 0; j < N; j++) {
                scanf("%d", &matrix[i][j]);
            }
        }
        count = 0;
        for (i = 0; i < N; i++) {
            for (j = 0; j < N; j++) {
                if (matrix[i][j] == 1) {
                    count++;
                }
            }
        }
        max_count = 0;
        for (i = 0; i < N; i++) {
            k = 0;
            for (j = 0; j < N; j++) {
                if (matrix[i][j] == 1) {
                    k++;
                }
            }
            if (k > max_count) {
                max_count = k;
            }
        }
        printf("%d\n", max_count - 1);
    }
    return 0;
}

